def ac3(csp):
    """Enforce arc consistency using AC-3 algorithm."""
    queue = []

    # Initialize queue with all arcs
    for Xi in csp.variables:
        for Xj in csp.neighbors[Xi]:
            queue.append((Xi, Xj))

    while queue:
        Xi, Xj = queue.pop(0)

        if revise(csp, Xi, Xj):
            # If domain reduced, add all arcs involving Xi
n            if len(csp.domains[Xi]) == 0:
                return False  # No solution possible

            for Xk in csp.neighbors[Xi]:
                if Xk != Xj:
                    queue.append((Xk, Xi))

    return True


def revise(csp, Xi, Xj):
    """Remove inconsistent values from Xi domain."""
    revised = False

    for x in csp.domains[Xi][:]:  # Copy to iterate safely
        # Check if any value in Xj supports x
        supported = False
        for y in csp.domains[Xj]:
            if csp.is_consistent(Xi, x, Xj, y):
                supported = True
                break

        if not supported:
            csp.domains[Xi].remove(x)
            revised = True

    return revised

