#define N 8

int board[N];  // board[i] = column of queen in row i

bool isSafe(int row, int col) {
    for (int i = 0; i < row; i++) {
        int j = board[i];
        // Check column and diagonals
        if (j == col || 
            j == col - (row - i) || 
            j == col + (row - i)) {
            return false;
        }
    }
    return true;
}

bool solveNQueens(int row) {
    if (row == N) {
        // Solution found - print it
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                printf("%c ", board[i] == j ? 'Q' : '.');
            }
            printf("\n");
        }
        printf("\n");
        return true;
    }

    for (int col = 0; col < N; col++) {
        if (isSafe(row, col)) {
            board[row] = col;

            if (solveNQueens(row + 1)) {
                return true;  // Find one solution
            }

            board[row] = -1;  // Backtrack
        }
    }

    return false;
}

int main() {
    for (int i = 0; i < N; i++) board[i] = -1;
    solveNQueens(0);
    return 0;
}

import java.util.*;

public class MinConflicts {

    public static Map<String, Integer> solve(Map<String, Set<Integer>> variables,
                                            Map<String, Set<String>> constraints,
                                            int maxSteps) {
        // Initialize with random complete assignment
        Map<String, Integer> assignment = new HashMap<>();
        Random rand = new Random();

        for (String var : variables.keySet()) {
            List<Integer> values = new ArrayList<>(variables.get(var));
            assignment.put(var, values.get(rand.nextInt(values.size())));
        }

        for (int step = 0; step < maxSteps; step++) {
            // Find all conflicted variables
            List<String> conflicted = getConflictedVars(assignment, constraints);

            if (conflicted.isEmpty()) {
                return assignment;  // Solution found!
            }

            // Pick random conflicted variable
            String var = conflicted.get(rand.nextInt(conflicted.size()));

            // Find value causing minimum conflicts
            int minConflicts = Integer.MAX_VALUE;
            List<Integer> bestValues = new ArrayList<>();

            for (int value : variables.get(var)) {
                assignment.put(var, value);
                int conflicts = countConflicts(var, assignment, constraints);

                if (conflicts < minConflicts) {
                    minConflicts = conflicts;
                    bestValues.clear();
                    bestValues.add(value);
                } else if (conflicts == minConflicts) {
                    bestValues.add(value);
                }
            }

            // Assign randomly among best values
            assignment.put(var, bestValues.get(rand.nextInt(bestValues.size())));
        }

        return null;  // No solution within maxSteps
    }

    private static int countConflicts(String var, Map<String, Integer> assignment,
                                       Map<String, Set<String>> constraints) {
        int count = 0;
        int value = assignment.get(var);

        for (String neighbor : constraints.getOrDefault(var, Collections.emptySet())) {
            if (assignment.containsKey(neighbor) && 
                assignment.get(neighbor).equals(value)) {
                count++;
            }
        }
        return count;
    }
}
